mapper.select:
select a.*,b.employee_name,b.job_number,b.post,c.name as deptName from hrm_attendance_clock a left join hrm_employee b on a.clock_employee_id = b.employee_id left join hrm_dept c on b.dept_id = c.dept_id where b.is_del = 0
and b.dept_id in
#{deptId}
and a.type in
#{type}
a.is_out_work=1
a.clock_status=#{data.clockStatus}
and date_format(a.clock_time,'%y-%m-%d') between date_format(#{data.times[0]},'%y-%m-%d') and date_format(#{data.times[1]},'%y-%m-%d')
and (b.employee_name like concat('%',#{data.search},'%') or b.job_number like concat('%',#{data.search},'%'))
and a.address like concat('%',#{data.address},'%')
and a.clock_type=#{data.clockType}
and a.clock_employee_id in
#{employeeId}
and 1=2
order by a.clock_employee_id,a.clock_time desc

select a.*,b.employee_name from hrm_attendance_clock a
left join hrm_employee b on a.clock_employee_id = b.employee_id
where date_format(attendance_time,'%Y-%m-%d') = #{time}

    
        and a.clock_employee_id in
        
            #{employeeId}
        
    
    
        and 1=2

select date_format(attendance_time,'%Y-%m-%d') from hrm_attendance_clock
where attendance_time between #{data.startTime} and #{data.endTime}

    
        and clock_employee_id in
        
            #{employeeId}
        
    
    
        and 1=2
    

group by date_format(attendance_time,'%Y-%m-%d')

select b.employee_id,b.employee_name,b.job_number,b.post,b.entry_time,b.`status`,b.work_city,b.company_age,c.name as deptName from hrm_employee b left join hrm_dept c on b.dept_id = c.dept_id where b.is_del = 0 and b.entry_status in(1,3) and b.entry_time<=sysdate()
and (b.employee_name like concat('%',#{data.search},'%') or b.job_number like concat('%',#{data.search},'%'))
and b.employee_id= #{data.employeeId}
and b.dept_id in
#{deptId}
and b.employee_id in
#{employeeId}
and 1=2
ORDER BY b.${data.sortField}
desc
asc
ORDER BY b.job_number asc

select t1.* from hrm_attendance_clock t1 inner join ( SELECT max(clock_id) as clockId FROM hrm_attendance_clock WHERE clock_type = #{clockType} and attendance_time between #{startDateTime} and #{endDateTime} and clock_stage = #{clockStage}
and clock_employee_id in
#{employeeId}
and 1=2
group by clock_employee_id,date_format(attendance_time,'%Y-%m-%d') ) t2 on t1.clock_id=t2.clockId

select clock_employee_id as employeeId,count(1) as nightShiftDays FROM ( SELECT t1.clock_employee_id, t1.clock_time, t1.attendance_time, t1.clock_type, t1.clock_stage, t2.work_date FROM hrm_attendance_clock t1 LEFT JOIN hrm_attendance_plan t2 ON t1.plan_id = t2.plan_id left join hrm_attendance_shift t3 on t1.class_id = t3.shift_id WHERE LEFT ( attendance_time, 10 )> LEFT ( t2.work_date, 10 ) AND t1.clock_type = '2' AND clock_time >= attendance_time
and t1.clock_employee_id=#{employeeId}
and t2.work_date >=#{beginDate} and t2.work_date <= #{endDate} AND HOUR ( attendance_time )>= #{checkHour} and t3.shift_hours>=8 ) T group by clock_employee_id
